  ('medical-tech-moex-21104', 'medical-tech', 'medical-tech-moex-093-5c00801d', 'sub-medical-tech-13', NULL, 'single_choice', '有關痢疾阿米巴（Entamoeba histolytica）與大腸阿米巴（Entamoeba coli）之滋養體（trophozoite）的比較， 下列何者正確？ 前者的偽足為鈍狀；後者的如指狀 前者的細胞質顆粒較粗；後者的較細 前者只吞噬細菌；後者卻吞噬紅血球 前者的核微體（karyosome）通常位於核中央；後者的通常位於核旁邊', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "c9542f67b3c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床鏡檢學(包括寄生蟲學)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
